      RustLib.instance.api.crateApiWalletWalletMelt(that: this, quote: quote);

  Future<MeltQuote> meltQuote({required String request}) => RustLib.instance.api
      .crateApiWalletWalletMeltQuote(that: this, request: request);

  Stream<MintQuote> mint({required BigInt amount, String? description}) =>
      RustLib.instance.api.crateApiWalletWalletMint(
        that: this,
        amount: amount,
        description: description,
      );

  /// Pay a NUT-18 payment request.
  /// Uses CDK's pay_request() which handles:
  /// - NUT-10 spending conditions
  /// - Transport selection (Nostr preferred, HTTP POST fallback)
  /// - Token preparation and delivery
  Future<void> payPaymentRequest({
    required String encoded,
    BigInt? customAmount,
  }) => RustLib.instance.api.crateApiWalletWalletPayPaymentRequest(
    that: this,
    encoded: encoded,
    customAmount: customAmount,
  );

  Future<PreparedSend> prepareSend({
    required BigInt amount,
    SendOptions? opts,
  }) => RustLib.instance.api.crateApiWalletWalletPrepareSend(
    that: this,
    amount: amount,
    opts: opts,
  );

  Future<BigInt> receive({required Token token, ReceiveOptions? opts}) =>
      RustLib.instance.api.crateApiWalletWalletReceive(
        that: this,
        token: token,
        opts: opts,
      );

  /// Check pending-spent proofs with the mint and revert unspent ones.
  /// Returns the number of proofs recovered.
  Future<BigInt> reclaimPendingProofs() =>
      RustLib.instance.api.crateApiWalletWalletReclaimPendingProofs(that: this);

  Future<void> recoverIncompleteSagas() => RustLib.instance.api
      .crateApiWalletWalletRecoverIncompleteSagas(that: this);

  Future<void> restore() =>
      RustLib.instance.api.crateApiWalletWalletRestore(that: this);

  Future<SendResult> send({
    required PreparedSend send,
    String? memo,
    bool? includeMemo,
  }) => RustLib.instance.api.crateApiWalletWalletSend(
    that: this,
    send: send,
    memo: memo,
    includeMemo: includeMemo,
  );

  Stream<BigInt> streamBalance() =>
      RustLib.instance.api.crateApiWalletWalletStreamBalance(that: this);

  /// Wait for an incoming Nostr payment (NIP-17 gift-wrap).
  ///
  /// Takes the opaque NostrListenerHandle returned by create_payment_request().
  /// The secret key never leaves Rust memory.
  Stream<NostrPaymentEvent> waitForNostrPayment({
    required NostrListenerHandle handle,
  }) => RustLib.instance.api.crateApiWalletWalletWaitForNostrPayment(
    that: this,
    handle: handle,
  );
}
